import{_ as a,o as s,c as n,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"UXS-002 — Mission Configurator","description":"","frontmatter":{},"headers":[],"relativePath":"uxs/UXS-002.md","filePath":"uxs/UXS-002.md"}'),t={name:"uxs/UXS-002.md"};function o(l,e,r,p,c,d){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="uxs-002-—-mission-configurator" tabindex="-1">UXS-002 — Mission Configurator <a class="header-anchor" href="#uxs-002-—-mission-configurator" aria-label="Permalink to &quot;UXS-002 — Mission Configurator&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Visual fidelity · Verified against prototype (P02_mission-configurator.html) IA anchor · §surfaces/plan · §topbar-patterns · §shared-tokens Related PRD · PRD-002 Related ADRs · ADR-008 (Lambert worker) Related RFCs · RFC-003 (Lambert worker protocol)</p></blockquote><h2 id="why-this-uxs-exists" tabindex="-1">Why this UXS exists <a class="header-anchor" href="#why-this-uxs-exists" aria-label="Permalink to &quot;Why this UXS exists&quot;">​</a></h2><p>The porkchop plot is a 2D colour-mapped grid. This UXS defines its visual encoding, the right panel that appears on cell selection, the vehicle selector, and the outcome display (viable vs delta-v deficit).</p><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ul><li>Blue = cheap, orange = expensive — intuitive before explanation</li><li>The selected cell is unambiguous against the colour field</li><li>Failure state (delta-v deficit) is visible and specific, not hidden</li><li>The right panel reads as a mission brief</li></ul><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>In scope: nav bar, porkchop canvas, axis labels, colour scale, selected cell highlight, right panel (vehicle selector, delta-v budget, FLY button), progress indicator during computation. Non-goals: date slider interaction timing, cell hover debounce. Boundary note: Lambert computation progress reporting belongs in RFC-003.</p><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p>Dark only.</p><h2 id="tokens" tabindex="-1">Tokens <a class="header-anchor" href="#tokens" aria-label="Permalink to &quot;Tokens&quot;">​</a></h2><h3 id="inherited-from-ia" tabindex="-1">Inherited from IA <a class="header-anchor" href="#inherited-from-ia" aria-label="Permalink to &quot;Inherited from IA&quot;">​</a></h3><p>All shared tokens.</p><h3 id="defined-here" tabindex="-1">Defined here <a class="header-anchor" href="#defined-here" aria-label="Permalink to &quot;Defined here&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>porkchop-min-dv:  hsl(210,90%,55%)   best windows — blue</span></span>
<span class="line"><span>porkchop-mid-dv:  hsl(45,90%,55%)    marginal — yellow</span></span>
<span class="line"><span>porkchop-max-dv:  hsl(20,90%,50%)    expensive — orange</span></span>
<span class="line"><span>porkchop-nosoln:  rgba(20,20,30,1)   no solution — near-black</span></span>
<span class="line"><span>selected-cell:    rgba(255,255,255,0.9) outline, 1.5px</span></span>
<span class="line"><span>axis-label:       rgba(255,255,255,0.4) 7px Space Mono</span></span>
<span class="line"><span>progress-bar:     linear-gradient(to right, #4466ff, #4ecdc4)</span></span>
<span class="line"><span>deficit-colour:   #ff6060</span></span>
<span class="line"><span>viable-colour:    #4ecdc4</span></span></code></pre></div><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  NAV BAR (52px)                                        │</span></span>
<span class="line"><span>├────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  Porkchop plot canvas                  │ Right panel   │</span></span>
<span class="line"><span>│  (fills remaining space minus panel)  │ (280px)       │</span></span>
<span class="line"><span>│                                        │               │</span></span>
<span class="line"><span>│  Y: arrival dates                      │ Mission brief │</span></span>
<span class="line"><span>│  X: departure dates                    │ Vehicle select│</span></span>
<span class="line"><span>│  Colour: delta-v                       │ Δv budget     │</span></span>
<span class="line"><span>│                                        │ FLY button    │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────┘</span></span></code></pre></div><p>Right panel: <code>background rgba(4,4,12,0.97)</code>, border-left <code>1px solid rgba(255,255,255,0.07)</code>, padding <code>16px 20px</code>.</p><h2 id="component-states" tabindex="-1">Component states <a class="header-anchor" href="#component-states" aria-label="Permalink to &quot;Component states&quot;">​</a></h2><p><strong>Cell (default):</strong> colour from delta-v cost, no outline <strong>Cell (hovered):</strong> tooltip showing dep date, arr date, transit, dv <strong>Cell (selected):</strong> white outline 1.5px; right panel populates <strong>Right panel (empty):</strong> &quot;SELECT A LAUNCH WINDOW&quot; hint text <strong>Right panel (viable):</strong> mission brief, vehicle dropdown, delta-v bar in teal, FLY button enabled <strong>Right panel (deficit):</strong> mission brief, vehicle dropdown, delta-v bar in red, deficit amount shown, FLY button disabled <strong>Progress bar (computing):</strong> gradient bar fills left-to-right, &quot;COMPUTING 11,200 TRAJECTORIES&quot; label <strong>FLY button (enabled):</strong> <code>background #1a33bb</code>, <code>border rgba(68,102,255,0.55)</code>, white text <strong>FLY button (disabled):</strong> <code>background rgba(255,255,255,0.05)</code>, <code>color rgba(255,255,255,0.25)</code></p><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>Canvas: <code>aria-label=&quot;Porkchop plot showing delta-v cost for departure and arrival date combinations&quot;</code></li><li>Right panel content is HTML — screen reader accessible</li><li>FLY button disabled state uses both visual and <code>aria-disabled=&quot;true&quot;</code></li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance criteria&quot;">​</a></h2><ul><li>[ ] Porkchop plot renders with correct colour mapping (blue valleys, orange peaks)</li><li>[ ] Selected cell has visible white outline</li><li>[ ] Right panel shows departure date, arrival date, transit time, delta-v on cell click</li><li>[ ] Vehicle dropdown changes delta-v budget calculation</li><li>[ ] Viable missions show teal delta-v bar and enabled FLY button</li><li>[ ] Deficit missions show red bar, deficit amount, disabled FLY button</li><li>[ ] Progress bar appears during Lambert computation</li><li>[ ] FLY button navigates to <code>/fly?mission=orrery-1</code> (or selected mission)</li></ul>`,24)])])}const b=a(t,[["render",o]]);export{u as __pageData,b as default};
